-- Add food preference columns to users table
ALTER TABLE users ADD COLUMN IF NOT EXISTS dietary_restrictions TEXT[] DEFAULT '{}';
ALTER TABLE users ADD COLUMN IF NOT EXISTS cuisine_preferences TEXT[] DEFAULT '{}';
ALTER TABLE users ADD COLUMN IF NOT EXISTS disliked_foods TEXT DEFAULT '';
ALTER TABLE users ADD COLUMN IF NOT EXISTS cooking_level TEXT DEFAULT 'moderate';

-- Create meal_recipes table
CREATE TABLE IF NOT EXISTS meal_recipes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  cuisine TEXT NOT NULL,
  meal_type TEXT NOT NULL CHECK (meal_type IN ('breakfast','lunch','dinner','snack')),
  calories INTEGER NOT NULL,
  protein INTEGER NOT NULL,
  carbs INTEGER NOT NULL,
  fat INTEGER NOT NULL,
  description TEXT NOT NULL,
  dietary_tags TEXT[] DEFAULT '{}',
  main_protein TEXT DEFAULT NULL,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE meal_recipes ENABLE ROW LEVEL SECURITY;

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_policies WHERE tablename = 'meal_recipes' AND policyname = 'meal_recipes_read_all'
  ) THEN
    CREATE POLICY "meal_recipes_read_all" ON meal_recipes FOR SELECT USING (true);
  END IF;
END $$;

